import { Meter as MeterPrimitive } from '@base-ui/react/meter';
import { forwardRef, type ComponentRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Meter.module.css';

const Meter = forwardRef<ComponentRef<typeof MeterPrimitive.Root>, MeterPrimitive.Root.Props>(
  function Meter({ children, ...props }, ref) {
    return (
      <MeterRoot ref={ref} {...props}>
        {children}
        <MeterTrack>
          <MeterIndicator />
        </MeterTrack>
      </MeterRoot>
    );
  },
);

const MeterRoot = forwardRef<ComponentRef<typeof MeterPrimitive.Root>, MeterPrimitive.Root.Props>(
  function MeterRoot({ className, ...props }, ref) {
    return (
      <MeterPrimitive.Root
        ref={ref}
        data-slot="meter-root"
        className={mergeClassName(className, styles.root)}
        {...props}
      />
    );
  },
);

const MeterLabel = forwardRef<
  ComponentRef<typeof MeterPrimitive.Label>,
  MeterPrimitive.Label.Props
>(function MeterLabel({ className, ...props }, ref) {
  return (
    <MeterPrimitive.Label
      ref={ref}
      data-slot="meter-label"
      className={mergeClassName(className, styles.label)}
      {...props}
    />
  );
});

const MeterValue = forwardRef<
  ComponentRef<typeof MeterPrimitive.Value>,
  MeterPrimitive.Value.Props
>(function MeterValue({ className, ...props }, ref) {
  return (
    <MeterPrimitive.Value
      ref={ref}
      data-slot="meter-value"
      className={mergeClassName(className, styles.value)}
      {...props}
    />
  );
});

const MeterTrack = forwardRef<
  ComponentRef<typeof MeterPrimitive.Track>,
  MeterPrimitive.Track.Props
>(function MeterTrack({ className, ...props }, ref) {
  return (
    <MeterPrimitive.Track
      ref={ref}
      data-slot="meter-track"
      className={mergeClassName(className, styles.track)}
      {...props}
    />
  );
});

const MeterIndicator = forwardRef<
  ComponentRef<typeof MeterPrimitive.Indicator>,
  MeterPrimitive.Indicator.Props
>(function MeterIndicator({ className, ...props }, ref) {
  return (
    <MeterPrimitive.Indicator
      ref={ref}
      data-slot="meter-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    />
  );
});

export { Meter, MeterRoot, MeterLabel, MeterValue, MeterTrack, MeterIndicator };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: var(--meter-gap, 0.5rem);
    width: var(--meter-width, 12rem);
    color: var(--meter-color, var(--color-foreground));
  }

  .label {
    color: var(--meter-label-color, currentColor);
    font-size: var(--meter-label-font-size, var(--text-sm));
    font-weight: var(--meter-label-font-weight, var(--weight-regular));
    line-height: var(--meter-label-line-height, var(--line-height-text-sm));
  }

  .value {
    justify-self: end;
    color: var(--meter-value-color, currentColor);
    font-size: var(--meter-value-font-size, var(--text-sm));
    font-weight: var(--meter-value-font-weight, var(--weight-regular));
    line-height: var(--meter-value-line-height, var(--line-height-text-sm));
    text-align: right;
  }

  .track {
    grid-column: 1 / -1;
    display: block;
    overflow: hidden;
    width: 100%;
    height: var(--meter-track-height, 0.5rem);
    border-radius: var(--meter-track-radius, var(--radius-full));
    background-color: var(--meter-track-bg, var(--color-muted));
    box-shadow: inset 0 0 0 var(--meter-track-border-width, var(--border-width-sm))
      var(--meter-track-border-color, var(--color-border));
  }

  .indicator {
    display: block;
    height: 100%;
    border-radius: var(--meter-indicator-radius, inherit);
    background-color: var(--meter-indicator-bg, var(--color-primary));
    transition: width var(--meter-indicator-transition, var(--transition-default));
  }
}
